import{_ as a,o as e,c as r,ag as o}from"./chunks/framework.-Wrcbzkw.js";const d=JSON.parse('{"title":"Unit1 am/iUnit 1: am / is / are (动词be的用法)","description":"","frontmatter":{},"headers":[],"relativePath":"English/《Essential Grammar in Use》/Unit1.md","filePath":"English/《Essential Grammar in Use》/Unit1.md","lastUpdated":1777676755000}'),i={name:"English/《Essential Grammar in Use》/Unit1.md"};function n(s,t,l,h,u,g){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="unit1-am-iunit-1-am-is-are-动词be的用法" tabindex="-1">Unit1 am/i<strong>Unit 1: am / is / are (动词be的用法)</strong> <a class="header-anchor" href="#unit1-am-iunit-1-am-is-are-动词be的用法" aria-label="Permalink to &quot;Unit1 am/i**Unit 1: am / is / are (动词be的用法)**&quot;">​</a></h1><h4 id="语法重点" tabindex="-1"><strong>语法重点</strong> <a class="header-anchor" href="#语法重点" aria-label="Permalink to &quot;**语法重点**&quot;">​</a></h4><p>在英语中，动词 &quot;be&quot; 是一个非常重要的系动词，用于连接主语和表语，表示状态、身份、位置等。根据主语的不同，&quot;be&quot; 变为不同的形式：am, is, 或 are。</p><h4 id="_1-主语与be动词的搭配" tabindex="-1"><strong>1. 主语与be动词的搭配</strong> <a class="header-anchor" href="#_1-主语与be动词的搭配" aria-label="Permalink to &quot;**1. 主语与be动词的搭配**&quot;">​</a></h4><ul><li><strong>I + am</strong> 例：I am a student. (我是一个学生。)</li><li><strong>he / she / it + is</strong> 例：She is my friend. (她是我的朋友。)</li><li><strong>you / we / they + are</strong> 例：They are teachers. (他们是教师。)</li></ul><h4 id="_2-否定形式" tabindex="-1"><strong>2. 否定形式</strong> <a class="header-anchor" href="#_2-否定形式" aria-label="Permalink to &quot;**2. 否定形式**&quot;">​</a></h4><p>在句子中使用 &quot;not&quot; 来形成否定句。</p><ul><li><strong>I am not</strong> 例：I am not a doctor. (我不是医生。)</li><li><strong>he / she / it is not (isn&#39;t)</strong> 例：He isn&#39;t here. (他不在这里。)</li><li><strong>you / we / they are not (aren&#39;t)</strong> 例：We aren&#39;t late. (我们不迟到。)</li></ul><h4 id="_3-疑问句形式" tabindex="-1"><strong>3. 疑问句形式</strong> <a class="header-anchor" href="#_3-疑问句形式" aria-label="Permalink to &quot;**3. 疑问句形式**&quot;">​</a></h4><p>用 &quot;am / is / are&quot; 放在句首来构成疑问句。</p><ul><li><strong>Am I...?</strong> 例：Am I late? (我迟到了吗？)</li><li><strong>Is he / she / it...?</strong> 例：Is she happy? (她开心吗？)</li><li><strong>Are you / we / they...?</strong> 例：Are they your friends? (他们是你的朋友吗？)</li></ul><h4 id="_4-其他常见用法" tabindex="-1"><strong>4. 其他常见用法</strong> <a class="header-anchor" href="#_4-其他常见用法" aria-label="Permalink to &quot;**4. 其他常见用法**&quot;">​</a></h4><ul><li>表示地点： <strong>The book is on the table.</strong> (书在桌子上。)</li><li>表示职业或身份： <strong>She is a teacher.</strong> (她是一个老师。)</li><li>表示时间： <strong>It is 5 o&#39;clock.</strong> (现在是五点。)</li></ul><h4 id="总结" tabindex="-1"><strong>总结</strong> <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;**总结**&quot;">​</a></h4><ul><li><strong>am</strong> 用于 &quot;I&quot; 主语。</li><li><strong>is</strong> 用于 &quot;he, she, it&quot; 主语。</li><li><strong>are</strong> 用于 &quot;you, we, they&quot; 主语。</li><li>否定句中使用 &quot;not&quot;。</li><li>疑问句中将 &quot;am / is / are&quot; 放在主语前。</li></ul><h4 id="常见练习" tabindex="-1"><strong>常见练习</strong> <a class="header-anchor" href="#常见练习" aria-label="Permalink to &quot;**常见练习**&quot;">​</a></h4><ol><li><strong>肯定句</strong>：She ___ a doctor. (is)</li><li><strong>否定句</strong>：They ___ late. (aren&#39;t)</li><li><strong>疑问句</strong>：___ you my friend? (Are)</li></ol>',17)])])}const _=a(i,[["render",n]]);export{d as __pageData,_ as default};
